{"content": "import SwiftUI
import OSLog

private let log = Logger(subsystem: "com.canvasapp.app", category: "StickerBar")

struct StickerBarView: View {
    let variants: [StickerVariant]
    let selectedVariant: String?
    var onSelect: ((StickerVariant, Bool) -> Void)?

    var body: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 10) {
                ForEach(variants) { item in
                    variantButton(item)
                }
            }
            .padding(.horizontal, 12)
            .padding(.vertical, 8)
        }
        .frame(height: 90)
        .background(.ultraThinMaterial)
        .clipShape(Capsule())
        .padding(.horizontal, 16)
        .padding(.bottom, 8)
    }

    private func variantButton(_ item: StickerVariant) -> some View {
        Button {
            log.debug("tapped variant=\(item.variant, privacy: .public) isEmoji=\(item.isEmoji)")
            onSelect?(item, item.isEmoji)
        } label: {
            VStack(spacing: 2) {
                if item.isEmoji {
                    Text(item.variant)
                        .font(.system(size: 40))
                        .frame(width: 50, height: 50)
                } else {
                    imageOrFallback(item.variant)
                }
            }
            .frame(width: 60, height: 60)
            .background(
                Circle()
                    .fill(selectedVariant == item.variant
                          ? Color.white.opacity(0.35)
                          : Color.white.opacity(0.15))
                    .frame(width: 60, height: 60)
            )
            .scaleEffect(selectedVariant == item.variant ? 1.15 : 1.0)
            .animation(.spring(response: 0.2), value: selectedVariant)
        }
        .buttonStyle(.plain)
    }

    @ViewBuilder
    private func imageOrFallback(_ name: String) -> some View {
        if let path = Bundle.main.path(forResource: name, ofType: "png", inDirectory: "Stickers"),
           let uiImage = UIImage(contentsOfFile: path) {
            let _ = log.debug("✅ path: \(name)")
            Image(uiImage: uiImage)
                .resizable()
                .aspectRatio(contentMode: .fit)
                .frame(width: 50, height: 50)
        } else if let uiImage = UIImage(named: "Stickers/\(name)") {
            let _ = log.debug("⚠️ UIImage(named:) fallback: \(name)")
            Image(uiImage: uiImage)
                .resizable()
                .aspectRatio(contentMode: .fit)
                .frame(width: 50, height: 50)
        } else {
            let _ = log.error("❌ FAIL: \(name)")
            Text(String(name.prefix(2)))
                .font(.system(size: 14, weight: .bold))
                .foregroundColor(.white.opacity(0.6))
        }
    }
}
